  ('social-worker-moex-06371', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'essay', '藥物濫用與成癮已經成為青少年一個嚴重的問題，何謂「藥物濫用與成癮」？青少
年用藥之原因為何？藥物成癮者有何行為表現？藥物濫用成癮之歷程與特徵為何？
目前處遇模式為何？請說明之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06372', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關青少年（11-21歲）喪親的反應，下列敘述何者錯誤？ 青少年中，原先與存活的父/母關係良好的，比關係不良的有較高的憂鬱分數 部分青少年在學校的成績，因死亡後習慣改變而變差 大部分青少年在手足死亡後，促進個人成長 同樣經歷喪親的手足大部分不能提供青少年幫忙', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06373', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '未曾探索價值，未對重要價值做出承諾的青少年，其自我認定是下列選項的那一種？ 認同迷失（認定擴散，identity diffusion）  未定（認定延期償付，moratorium） 閉鎖（認定喪失主權，foreclosure）  認同達成（identity achievement）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06374', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '成功老化的關鍵，下列敘述何者錯誤？ 避免疾病及身心障礙    維持傳統生活型態 持續從事生產性活動    維持身體和心理功能的良好運作', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06375', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '中年照護者的壓力源，下列敘述何者錯誤？ 因中年人擔負一些照護職責，權力由年邁的父母手中轉移至中年子女手上 財務上，需提供父母親援助，也要支付子女的大學學費和自己的退休儲備金 多重角色相互競爭，同時是員工、學生、志工、母親、伴侶和家庭主婦 自己也面對死亡的焦慮及多重失落', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06376', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '自殺問題是社工處遇相當重要的議題，有關自殺之敘述，下列何者錯誤？ 失落事件引起的絕望，是自殺的重要原因 想要自殺的人多半會求救 大部分自殺的人都會採用上吊、臥軌、舉槍等激烈的自我傷害方式 自殺事件結束後，平常心與當事人互動，是最好的應對之道', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06377', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '遊民問題是當前的重要社會現象，下列那一項敘述正確？ 成為遊民的因素主要是精神疾病、藥物濫用等疾病問題 遊民都是失業者 成為遊民通常是個人及社會因素合併作用所致 目前臺灣的遊民收容所的空間足以安置遊民', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06378', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '小明10歲，成長於單親家庭，父親經常酗酒且失業，酒後並毆打腦性麻痺的小明。針對這個個案，請問 下列何者不是社工的工作？ 通報家暴中心    連繫身心障礙個案管理師 連結社會資源    專業醫療諮詢', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06379', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關中輟生的成因，下列敘述何者錯誤？ 個人因素，自我概念差，學習困難，未婚懷孕 遺傳因素，因先天體質差，基因有問題 家庭因素，父母疏於管教，家庭社經地位低，親子關係不良 同儕團體因素，受不良同學影響或引誘；與同學關係不佳；受欺壓不敢上學', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
